def min_operations_to_portal(t, test_cases):
    results = []

    for case in range(t):
        n, m, grid = test_cases[case]

        # Initialize the minimum operations to a large number
        min_operations = float('inf')

        # Iterate over all possible top-left corners (i, j) of sub-rectangles
        for i in range(n - 4):
            for j in range(m - 3):
                # Try all possible sizes a and b
                for a in range(5, n - i + 1):
                    for b in range(4, m - j + 1):
                        # Calculate the number of operations needed for this sub-rectangle
                        operations = 0

                        # Check the border conditions
                        # Top and bottom rows
                        for x in range(1, b - 1):
                            if grid[i][j + x] == '0':
                                operations += 1
                            if grid[i + a - 1][j + x] == '0':
                                operations += 1

                        # Left and right columns
                        for y in range(1, a - 1):
                            if grid[i + y][j] == '0':
                                operations += 1
                            if grid[i + y][j + b - 1] == '0':
                                operations += 1

                        # Check the inner part
                        for x in range(1, a - 1):
                            for y in range(1, b - 1):
                                if grid[i + x][j + y] == '1':
                                    operations += 1

                        # Update the minimum operations
                        min_operations = min(min_operations, operations)

        # Store the result for the current test case
        results.append(min_operations)

    return results

