def minimal_difference(t, test_cases):
    results = []
    for a, b, c in test_cases:
        total_duration = a * 1 + b * 2 + c * 3
        target = total_duration // 2

        # Initialize DP array
        dp = [False] * (target + 1)
        dp[0] = True

        # Process 1-minute songs
        for _ in range(a):
            for j in range(target, 0, -1):
                if j >= 1:
                    dp[j] = dp[j] or dp[j - 1]

        # Process 2-minute songs
        for _ in range(b):
            for j in range(target, 1, -1):
                if j >= 2:
                    dp[j] = dp[j] or dp[j - 2]

        # Process 3-minute songs
        for _ in range(c):
            for j in range(target, 2, -1):
                if j >= 3:
                    dp[j] = dp[j] or dp[j - 3]

        # Find the closest possible duration to target
        for j in range(target, -1, -1):
            if dp[j]:
                closest_duration = j
                break

        # Calculate the minimal possible difference
        min_difference = abs(total_duration - 2 * closest_duration)
        results.append(min_difference)

    return results

